const dadosIa = $input.item.json;

let cidade = dadosIa.cidade || '';
let uf = dadosIa.uf || '';
let limite = dadosIa.limite || 20;

// Se a IA mandou tudo num campo "query" (ex: "Diadema, SP" ou "Diadema - SP")
if (dadosIa.query && !cidade) {
    let partes = dadosIa.query.split(/,| - |-/); // Separa usando vírgula ou traço
    cidade = partes[0] ? partes[0].trim() : '';
    uf = partes[1] ? partes[1].trim() : '';
}

// Retorna limpo e com fallbacks de segurança
return {
    json: {
        cidade: cidade || 'Birigui',
        uf: uf || 'SP',
        limite: limite
    }
};

// Função para corrigir caracteres corrompidos (UTF-8 vs ISO-8859-1)
function fixEncoding(text) {
    if (typeof text !== 'string') return text;
    try {
        // Tenta converter a string "mojibake" de volta para bytes e redecodificar
        return decodeURIComponent(escape(text));
    } catch (e) {
        // Se falhar (ex: texto já está ok), limpa manualmente os padrões comuns de erro
        return text
            .replace(/茫/g, 'ã')
            .replace(/茅/g, 'é')
            .replace(/铆/g, 'í')
            .replace(/贸/g, 'ó')
            .replace(/煤/g, 'ú')
            .replace(/锚/g, 'ê')
            .replace(/芒/g, 'â')
            .replace(/ Igreja/g, 'ç') // Caso o ç também esteja quebrado
            .replace(/SA煤de/g, 'Saúde');
    }
}

const leadsBrutos = $input.item.json.retorno || [];

const leadsFiltrados = leadsBrutos.map(lead => ({
    // Identificação Básica
    empresa: fixEncoding(lead.razaoSocial),
    nomeFantasia: fixEncoding(lead.nomeFantasia),

    // Localização para o Roteiro
    endereco: fixEncoding(lead.enderecoCompleto),
    bairro: fixEncoding(lead.bairro),
    cidade: fixEncoding(lead.cidade),
    tipoLogradouro: lead.tipoLogradouro,

    // Contatos diretos
    telefones: lead.telefones || [],
    emails: lead.emails || [],

    // Mídia (Fotos para o agente)
    fotos: lead.fotos || [],

    // Presença Digital e Redes Sociais
    redesSociais: lead.redesSociais || [],
    possuiPresencaDigital: lead.possuiPresencaDigital,

    // Inteligência de Vendas
    faturamento: lead.indicadorAtividade?.faixaFaturamento,
    natureza: fixEncoding(lead.naturezaJuridica),
    score: {
        nota: lead.notaICP,
        classificacao: lead.classificacaoICP,
        descricao: fixEncoding(lead.descricaoClassificacaoICP)
    }
}));

return { json: { leads: leadsFiltrados } };
